import hashlib


def hash_password(algorithm_name, message):
    """
    Hash the given message using the specified algorithm.

    Args:
        algorithm_name (str): Name of the hashing algorithm (e.g., 'sha256').
        message (str | bytes | bytearray | memoryview): Data to hash.

    Returns:
        bytes: The hash digest.
    """
    if not isinstance(algorithm_name, str):
        raise TypeError("algorithm_name must be a str")
    algo = algorithm_name.lower()

    if isinstance(message, bytes):
        data = message
    elif isinstance(message, bytearray):
        data = bytes(message)
    elif isinstance(message, memoryview):
        data = message.tobytes()
    elif isinstance(message, str):
        data = message.encode("utf-8")
    else:
        raise TypeError("message must be of type str, bytes, bytearray, or memoryview")

    try:
        return hashlib.new(algo, data).digest()
    except ValueError as e:
        raise ValueError(f"Unsupported hash algorithm: {algorithm_name}") from e

turn2_code:
import hashlib


def hash_password(algorithm_name, message):
    """
    Hash the given message using the specified algorithm.

    Args:
        algorithm_name (str): Name of the hashing algorithm (e.g., 'sha256').
        message (str | bytes | bytearray | memoryview): Data to hash.

    Returns:
        bytes: The hash digest.

    Raises:
        TypeError: If inputs are of incorrect types.
        ValueError: If the algorithm is unsupported.
    """
    if not isinstance(algorithm_name, str):
        raise TypeError("algorithm_name must be a str")
    algo = algorithm_name.lower()

    # Prepare data as bytes
    if isinstance(message, bytes):
        data = message
    elif isinstance(message, bytearray):
        data = bytes(message)
    elif isinstance(message, memoryview):
        data = message.tobytes()
    elif isinstance(message, str):
        data = message.encode("utf-8")
    else:
        raise TypeError("message must be of type str, bytes, bytearray, or memoryview")

    # Determine supported algorithms, excluding variable-length digest algorithms (SHAKE)
    supported_algorithms = {a.lower() for a in hashlib.algorithms_available}
    unsupported_variable_length = {"shake_128", "shake_256"}
    supported_algorithms -= unsupported_variable_length

    if algo not in supported_algorithms:
        raise ValueError(
            f"Unsupported hash algorithm: {algorithm_name}. "
            f"Supported algorithms: {', '.join(sorted(supported_algorithms))}"
        )

    try:
        return hashlib.new(algo, data).digest()
    except ValueError as e:
        # Fallback in case environment-specific issues arise with hashlib.new
        raise ValueError(f"Unsupported hash algorithm: {algorithm_name}") from e

turn1_code:
import hashlib


def hash_password(algorithm_name: str, raw_password: str) -> str:
    """
    Hash a password using the specified algorithm and return its hex digest.

    Args:
        algorithm_name: Name of the hash algorithm (e.g., 'sha256', 'sha512', etc.)
        raw_password: The password to hash.

    Returns:
        Hexadecimal string of the hashed password.

    Raises:
        ValueError: If the specified algorithm is not supported.
    """
    if not isinstance(algorithm_name, str) or not isinstance(raw_password, str):
        raise ValueError("algorithm_name and raw_password must be strings")

    name = algorithm_name.lower()
    available = {alg.lower() for alg in hashlib.algorithms_available}

    if name not in available:
        raise ValueError(f"Unsupported hash algorithm: {algorithm_name}")

    data = raw_password.encode("utf-8")

    # SHAKE algorithms require an explicit digest length for hex output.
    if name == "shake_128":
        # 32 bytes -> 64 hex chars (conventional default)
        return hashlib.new(name, data).hexdigest(32)
    if name == "shake_256":
        # 64 bytes -> 128 hex chars (conventional default)
        return hashlib.new(name, data).hexdigest(64)

    # Fixed-length algorithms support hexdigest() without specifying size.
    return hashlib.new(name, data).hexdigest()
